  font-family: 'DM Sans', sans-serif;
  max-width: 1200px;
  margin: 0 auto;
}

/* === Footer Heading === */
.suggested-reading--footer .sr-sidebar-heading {
  font-size: 1.125rem;
  font-weight: 800;
  margin-bottom: 2rem;
  color: #111;
  border-left: 3px solid #6b0b0b;
  padding-left: 0.75rem;
}

/* === Grid Layout === */
.suggested-reading--footer .sr-card-list {
  display: grid;
  grid-template-columns: repeat(auto-fit, minmax(240px, 1fr));
  gap: 2rem;
  padding: 0;
  margin: 0;
  list-style: none;
}

