.suggested-reading--footer .sr-card {
  display: flex;
  flex-direction: column;
  height: 100%;
}

/* === Inner Stack === */
.suggested-reading--footer .sr-card-inner {
  display: flex;
  flex-direction: column;
  justify-content: flex-start;
  flex: 1;
  gap: 0.5rem;
}

/* === Card Thumbnail === */
.suggested-reading--footer .sr-card-thumb {
  width: 100%;
  height: 140px;
  overflow: hidden;
  border-radius: 4px;
  background-color: #eee;
  line-height: 0;
  margin-bottom: 0 !important;
}

.suggested-reading--footer .sr-card-thumb img,
.suggested-reading--footer .sr-card-image {
  width: 100%;
