.suggested-reading--footer .sr-card-meta {
  margin-top: 0 !important;
  display: flex;
  flex-direction: column;
  gap: 0.25rem;
}

/* === Category === */
.suggested-reading--footer .sr-card-category {
  font-size: 0.85rem;
  color: #8a8a8a;
  font-weight: 500;
}

/* === Title === */
.suggested-reading--footer .sr-card-title {
  font-size: 1rem;
  font-weight: 800;
  color: #222;
  line-height: 1.4;
  margin: 0;
  font-family: 'DM Sans', sans-serif;
  display: -webkit-box;
  -webkit-line-clamp: 2;
  -webkit-box-orient: vertical;
  overflow: hidden;
  text-overflow: ellipsis;
}

.suggested-reading--footer .sr-card-title:hover {
  text-decoration: underline;
}

/* === Link Normalization === */
.suggested-reading--footer .sr-card-thumb-link,
.suggested-reading--footer .sr-card-title-link,
.suggested-reading--footer .sr-card-link {
  text-decoration: none;
  color: inherit;
  display: block;
}

/* === Responsive === */
@media (max-width: 768px) {
  .suggested-reading--footer {
    padding: 2rem 1rem;
  }

  .suggested-reading--footer .sr-card-thumb {
    height: 120px;
  }

  .suggested-reading--footer .sr-card-title {
    font-size: 0.95rem;
  }
}
